import numpy as np

def f(x, y):
    return x**2 + x*y + y**2

def partial_x(f, x, y, h=1e-5):
    return (f(x + h, y) - f(x - h, y)) / (2 * h)

def partial_y(f, x, y, h=1e-5):
    return (f(x, y + h) - f(x, y - h)) / (2 * h)

x0, y0 = 1.0, 2.0
print('analytic:', 2*x0 + y0, x0 + 2*y0)
print('numerical:', partial_x(f, x0, y0), partial_y(f, x0, y0))
